    "gradient": "from-teal-500/85 to-emerald-800/90",
    "thumbnailUrl": "https://images.unsplash.com/photo-1712651070043-0b8dbb843144?ixid=M3w5NDc5OTZ8MHwxfHNlYXJjaHwxfHxLb3JlYW4lMjBzcGElMjBhbmQlMjBqamltamlsYmFuZyUyMGd1aWRlJTIwZm9yJTIwZm9yZWlnbmVycyUyMEtvcmVhfGVufDB8MHx8fDE3Nzg2MTcxNDF8MA&ixlib=rb-4.1.0&w=800&q=80&auto=format&fit=crop",
