    "thumbnailUrl": "https://images.unsplash.com/photo-1577991712260-4ee45603dab8?ixid=M3w5NDc5OTZ8MHwxfHNlYXJjaHwxfHxob3clMjB0byUyMGJ1eSUyMEstcG9wJTIwbWVyY2hhbmRpc2UlMjBpbiUyMEtvcmVhJTIwS29yZWF8ZW58MHwwfHx8MTc3ODYxOTI0NHww&ixlib=rb-4.1.0&w=800&q=80&auto=format&fit=crop",
